using System;
using System.Text;

namespace Unity.FoxgloveSDK.Schemas
{
    /// <summary>
    /// Official foxglove JSON Schema constants and registration.
    /// Source: foxglove-sdk main@b298c3d1649e6e5dfd77a53b12ab7c27f97c7aba
    /// Schema content stored as base64-encoded C# constants — no runtime file I/O.
    /// </summary>
    public static class FoxgloveSchemaDefinitions
    {
        public const string FrameTransformSchemaName = "foxglove.FrameTransform";
        public const string SceneUpdateSchemaName = "foxglove.SceneUpdate";
        public const string CompressedImageSchemaName = "foxglove.CompressedImage";
        public const string JsonSchemaEncoding = "jsonschema";

        /// <summary>FrameTransform.json sha256=9986de138717bfaf</summary>
        private const string FrameTransformSchemaB64 =
            "";

        /// <summary>SceneUpdate.json sha256=7530dfd8585239e5</summary>
        private const string SceneUpdateSchemaB64 =
            "";

        /// <summary>CompressedImage.json sha256=f240ea31d2f0454b</summary>
        private const string CompressedImageSchemaB64 =
            "";

        public static readonly string FrameTransformSchema =
            Encoding.UTF8.GetString(Convert.FromBase64String(FrameTransformSchemaB64));

        public static readonly string SceneUpdateSchema =
            Encoding.UTF8.GetString(Convert.FromBase64String(SceneUpdateSchemaB64));

        public static readonly string CompressedImageSchema =
            Encoding.UTF8.GetString(Convert.FromBase64String(CompressedImageSchemaB64));

        /// <summary>
        /// Register core foxglove schemas into a registry. Idempotent (overwrites on duplicate name).
        /// </summary>
        public static void RegisterCoreSchemas(ISchemaRegistry registry)
        {
            if (registry == null)
                throw new ArgumentNullException(nameof(registry));

            registry.Register(new SchemaEntry
            {
                Name = FrameTransformSchemaName,
                Encoding = JsonSchemaEncoding,
                Content = FrameTransformSchema
            });

            registry.Register(new SchemaEntry
            {
                Name = SceneUpdateSchemaName,
                Encoding = JsonSchemaEncoding,
                Content = SceneUpdateSchema
            });

            registry.Register(new SchemaEntry
            {
                Name = CompressedImageSchemaName,
                Encoding = JsonSchemaEncoding,
                Content = CompressedImageSchema
            });
        }
    }
}
